const fs = require("fs");
const path = require("path");

// Data layer for /geneva-reflections. All numbers come from
// site-data/results.json, which is generated by scripts/analyze.py from the
// Pol.is exports in data/. Editorial copy lives in site-data/content.json and
// references statements by id only. See src/site/geneva-reflections/README.md.
const SITE_DATA = path.join(__dirname, "../../../site-data");

function readJson(name) {
  return JSON.parse(fs.readFileSync(path.join(SITE_DATA, name), "utf-8"));
}

module.exports = () => {
  const results = readJson("results.json");
  const content = readJson("content.json");
  const qv = readJson("qv-results.json");

  results.participation.total_votes_display =
    results.participation.total_votes.toLocaleString("en-US");

  qv.byId = Object.fromEntries(qv.principles.map((p) => [p.id, p]));
  qv.maxCredits = Math.max(
    1,
    ...qv.principles.map((p) => (p.credits == null ? 0 : p.credits))
  );

  return { results, content, qv };
};
